// // This module implements a 8-bit register with load and clear functionality. The register should load a new value when the `LOAD` signal is low. The register should clear to 0 when the `CLR` signal is low. When neither `LOAD` nor `CLR` is low, the register holds its current value.
module register(CLK, CLR, LOAD, DATA_IN, DATA_OUT);
input CLK, CLR, LOAD;
input [7:0] DATA_IN;
output [7:0] DATA_OUT;
reg [7:0] DATA_OUT;

always @(posedge CLK or posedge CLR) begin
    if (CLR)
        DATA_OUT <= 0;
    else if (LOAD)
        DATA_OUT <= DATA_IN;
end

endmodule
